// ---------------------------------------------------------------------------
// COMPETITOR REGISTRY
// The only place you edit to add/remove a competitor. Every downstream node
// is generic and reads from these fields, so nothing else needs to change.
// ---------------------------------------------------------------------------
const PRIMARY_COMPANY = 'OpenAI';
const LOOKBACK_HOURS  = 48;   // how far back an item may be dated
const MAX_ITEMS_PER_RUN = 40; // hard cap on LLM calls per run (cost guard)

const COMPETITORS = [
  { company: 'Anthropic',       github_org: 'anthropics',      news_query: 'Anthropic Claude AI',
    blog_rss: 'https://news.google.com/rss/search?q=site:anthropic.com&hl=en-US&gl=US&ceid=US:en' },
  { company: 'Google DeepMind', github_org: 'google-deepmind', news_query: '"Google DeepMind"',
    blog_rss: 'https://deepmind.google/blog/feed/basic/' },
  { company: 'xAI',             github_org: 'xai-org',         news_query: 'xAI Grok',
    blog_rss: 'https://news.google.com/rss/search?q=site:x.ai&hl=en-US&gl=US&ceid=US:en' },
  { company: 'Perplexity',      github_org: 'perplexityai',    news_query: 'Perplexity AI',
    blog_rss: 'https://news.google.com/rss/search?q=site:perplexity.ai&hl=en-US&gl=US&ceid=US:en' },
  { company: 'Mistral AI',      github_org: 'mistralai',       news_query: '"Mistral AI"',
    blog_rss: 'https://news.google.com/rss/search?q=site:mistral.ai&hl=en-US&gl=US&ceid=US:en' },
  { company: 'Cohere',          github_org: 'cohere-ai',       news_query: 'Cohere AI',
    blog_rss: 'https://news.google.com/rss/search?q=site:cohere.com&hl=en-US&gl=US&ceid=US:en' },
];

const now = new Date();
const cutoffMs = now.getTime() - LOOKBACK_HOURS * 3600 * 1000;

return COMPETITORS.map((c) => ({
  json: {
    ...c,
    primary_company: PRIMARY_COMPANY,
    lookback_hours: LOOKBACK_HOURS,
    max_items_per_run: MAX_ITEMS_PER_RUN,
    cutoff_iso: new Date(cutoffMs).toISOString(),
    cutoff_epoch: Math.floor(cutoffMs / 1000),
    run_date: now.toISOString().slice(0, 10),
    run_started_at: now.toISOString(),
  },
}));

// ---------------------------------------------------------------------------
// NORMALIZER
// Four sources, four completely different payload shapes -> one schema:
//   { company, source, category, title, date, url, content, fingerprint }
//
// Every branch is defensive. A node that failed with continueOnFail arrives
// here as { error: ... }; we convert it into a tagged _fetch_error item so the
// IF node downstream can route it to the error log instead of killing the run.
//
// FINGERPRINT NOTE: we deliberately do NOT dedupe on URL alone. Google News
// returns opaque news.google.com redirect tokens, so the same story arriving
// from two feeds has two different URLs. We hash company + normalized title +
// publisher host instead, which survives that.
// ---------------------------------------------------------------------------
const ctx      = $('Loop Over Competitors').first().json;
const company  = ctx.company;
const cutoffMs = ctx.cutoff_epoch * 1000;
const out      = [];

function fingerprint(title, url) {
  const norm = String(title || '')
    .toLowerCase().replace(/[^a-z0-9 ]/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 120);
  let host = 'unknown';
  try { host = new URL(url).hostname.replace(/^www\./, ''); } catch (e) { /* keep default */ }
  const raw = company + '|' + norm + '|' + host;
  let h = 5381;                                    // djb2, deterministic, no imports
  for (let i = 0; i < raw.length; i++) h = ((h << 5) + h + raw.charCodeAt(i)) >>> 0;
  return company.toLowerCase().replace(/\s+/g, '-') + '-' + h.toString(16);
}

function clean(s) {
  return String(s || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
}

function push(source, category, title, date, url, content) {
  if (!title || !url) return;
  const ts = Date.parse(date);
  const when = Number.isFinite(ts) ? ts : Date.now();
  if (when < cutoffMs) return;                     // outside the lookback window
  out.push({ json: {
    company, source, category,
    title:   clean(title).slice(0, 300),
    date:    new Date(when).toISOString(),
    url:     String(url),
    content: clean(content).slice(0, 2500),
    fingerprint: fingerprint(title, url),
    run_date: ctx.run_date,
    collected_at: new Date().toISOString(),
    _fetch_error: false,
  }});
}

function fail(source, message) {
  out.push({ json: {
    company, source, _fetch_error: true,
    error_message: String(message).slice(0, 500),
    run_date: ctx.run_date,
    collected_at: new Date().toISOString(),
  }});
}

for (const item of $input.all()) {
  const d = item.json || {};

  if (d.error) { fail(d._source || 'upstream_fetch', d.error.message || d.error); continue; }

  try {
    // --- Hacker News (Algolia returns ONE object containing a hits array) ---
    if (Array.isArray(d.hits)) {
      for (const h of d.hits) {
        push('hacker_news', 'community', h.title, h.created_at,
             h.url || 'https://news.ycombinator.com/item?id=' + h.objectID,
             'HN: ' + (h.points || 0) + ' points, ' + (h.num_comments || 0) + ' comments.');
      }
      continue;
    }

    // --- Google News (XML node output) ---
    if (d.rss && d.rss.channel) {
      const raw = d.rss.channel.item || [];
      for (const n of (Array.isArray(raw) ? raw : [raw])) {
        push('google_news', 'news', n.title, n.pubDate, n.link, n.description);
      }
      continue;
    }

    // --- GitHub (array response -> n8n already split it into items) ---
    if (d.full_name && d.html_url) {
      push('github', 'product_change',
           d.full_name + ': ' + (d.description || 'repository updated'),
           d.pushed_at, d.html_url,
           'Stars ' + (d.stargazers_count || 0) + '. Language ' + (d.language || 'n/a') +
           '. ' + (d.description || ''));
      continue;
    }

    // --- Company blog (RSS Feed Read output) ---
    if (d.link && (d.isoDate || d.pubDate)) {
      push('company_blog', 'blog', d.title, d.isoDate || d.pubDate, d.link,
           d.contentSnippet || d.content || d.summary);
      continue;
    }
  } catch (e) {
    fail('normalizer', e.message);
  }
}

// Never return zero items - the loop needs at least one item to continue.
if (out.length === 0) {
  out.push({ json: { company, source: 'none', _fetch_error: false, _empty: true,
                     run_date: ctx.run_date, collected_at: new Date().toISOString() }});
}
return out;

// ---------------------------------------------------------------------------
// Runs once, on the loop's "done" output, with every competitor's items pooled.
// Collapses cross-competitor duplicates, sorts newest first, caps the batch.
// ---------------------------------------------------------------------------
const seen = new Set();
const kept = [];

for (const item of $input.all()) {
  const d = item.json;
  if (d._fetch_error || d._empty || !d.fingerprint) continue;
  if (seen.has(d.fingerprint)) continue;
  seen.add(d.fingerprint);
  kept.push(d);
}

kept.sort((a, b) => Date.parse(b.date) - Date.parse(a.date));

const cap = $('Build Competitor Registry').first().json.max_items_per_run || 40;
return kept.slice(0, cap).map((json) => ({ json }));

// ---------------------------------------------------------------------------
// IDEMPOTENCY GATE
// Anything whose fingerprint already exists in the seen_ledger sheet is
// dropped. Re-running this workflow ten times on the same day produces exactly
// one set of rows and one email - the second run finds nothing new.
// ---------------------------------------------------------------------------
const ledger = new Set(
  $input.all()
    .map((r) => String(r.json.fingerprint || '').trim())
    .filter(Boolean)
);

const candidates = $('Dedupe & Sort').all();
const fresh = candidates.filter((c) => !ledger.has(c.json.fingerprint));

if (fresh.length === 0) {
  return [{ json: { _no_new_items: true, checked: candidates.length,
                    ledger_size: ledger.size } }];
}
return fresh;

// ---------------------------------------------------------------------------
// AI OUTPUT VALIDATION + DETERMINISTIC PRIORITY RULES
//
// Two jobs:
//  1. Never let a malformed / empty LLM response flow downstream. If parsing
//     fails we degrade gracefully to a placeholder row rather than crashing.
//  2. Priority is decided by RULES, not by the model. The LLM scores threat and
//     opportunity; the business decides what "Critical" means. This keeps the
//     exec report consistent run-to-run even if the model drifts.
// ---------------------------------------------------------------------------
const source = $('Filter Already Seen').all();
const out = [];

function clamp(v, lo, hi, dflt) {
  const n = Number(v);
  return Number.isFinite(n) ? Math.min(hi, Math.max(lo, Math.round(n))) : dflt;
}

function coerce(raw) {
  if (raw && typeof raw === 'object') return raw;
  if (typeof raw !== 'string') return null;
  const cleaned = raw.replace(/```json\n?|\n?```/g, '').trim();
  try { return JSON.parse(cleaned); } catch (e) { /* fall through */ }
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) { try { return JSON.parse(match[0]); } catch (e) { /* give up */ } }
  return null;
}

$input.all().forEach((item, i) => {
  const base = (source[i] && source[i].json) || {};
  const a = coerce(item.json.output !== undefined ? item.json.output : item.json) || {};
  const parseFailed = !a.summary;

  // --- Deterministic priority rules -----------------------------------------
  const hay = ((base.title || '') + ' ' + (base.content || '')).toLowerCase();
  let priority = 'Low';
  if (/\b(raises|raised|funding round|series [a-e]|valuation|acquires)\b/.test(hay)) priority = 'Medium';
  if (/\b(pricing|price cut|per million tokens|free tier|now costs|cheaper)\b/.test(hay)) priority = 'High';
  if (/\b(hiring spree|now hiring|headcount|open roles|expands team)\b/.test(hay))      priority = 'High';
  if (/\b(launch(es|ed|ing)?|announc\w+|introduc\w+|new model|general availability|ga release)\b/.test(hay)) priority = 'Critical';

  const threat      = clamp(a.threat_level, 1, 10, 3);
  const opportunity = clamp(a.opportunity_level, 1, 10, 3);

  // A rule can promote priority but the model's own high threat score can too.
  if (threat >= 8 && priority !== 'Critical') priority = 'Critical';

  out.push({ json: {
    run_date:           base.run_date,
    company:            base.company,
    source:             base.source,
    title:              base.title,
    url:                base.url,
    date:               base.date,
    fingerprint:        base.fingerprint,
    category:           a.category || base.category || 'other',
    summary:            a.summary || ('[AI analysis unavailable] ' + (base.title || '')),
    business_impact:    a.business_impact  || 'Not assessed.',
    customer_impact:    a.customer_impact  || 'Not assessed.',
    sentiment:          a.sentiment || 'neutral',
    threat_level:       threat,
    opportunity_level:  opportunity,
    impact_score:       Math.round((threat * 0.6 + opportunity * 0.4) * 10) / 10,
    priority:           priority,
    recommended_action: a.recommended_action || 'Review manually - AI produced no action.',
    confidence:         clamp(a.confidence, 1, 10, parseFailed ? 1 : 5),
    executive_summary:  a.executive_summary || a.summary || base.title,
    ai_parse_failed:    parseFailed,
  }});
});

return out;

// ---------------------------------------------------------------------------
// HTML EXECUTIVE REPORT
// Inline styles only - Gmail/Outlook strip <style> blocks. Tables for layout
// for the same reason. Sections are ordered by priority; empty ones are hidden.
// ---------------------------------------------------------------------------
const rows = ($json.items || []).slice();
rows.sort((a, b) => (a.priority_rank - b.priority_rank) || (b.impact_score - a.impact_score));

const runDate = rows.length ? rows[0].run_date : new Date().toISOString().slice(0, 10);
const companies = [...new Set(rows.map((r) => r.company))];
const criticals = rows.filter((r) => r.priority === 'Critical');
const avgThreat = rows.length
  ? (rows.reduce((s, r) => s + r.threat_level, 0) / rows.length).toFixed(1) : '0.0';

const esc = (s) => String(s == null ? '' : s)
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');

function card(r) {
  return `
  <tr><td style="padding:0 0 14px 0;">
    <table width="100%" cellpadding="0" cellspacing="0" style="border-left:4px solid ${r.priority_colour};background:#fafafa;border-radius:3px;">
      <tr><td style="padding:14px 16px;">
        <div style="font:600 11px/1 -apple-system,Segoe UI,Roboto,sans-serif;color:${r.priority_colour};letter-spacing:.08em;text-transform:uppercase;">
          ${esc(r.company)} &nbsp;&middot;&nbsp; ${esc(r.category)} &nbsp;&middot;&nbsp; ${esc(r.source)}
        </div>
        <div style="font:600 16px/1.35 -apple-system,Segoe UI,Roboto,sans-serif;color:#1a1a1a;margin:7px 0 6px;">
          <a href="${esc(r.url)}" style="color:#1a1a1a;text-decoration:none;">${esc(r.title)}</a>
        </div>
        <div style="font:400 14px/1.55 -apple-system,Segoe UI,Roboto,sans-serif;color:#3c4043;">${esc(r.summary)}</div>
        <div style="font:400 13px/1.55 -apple-system,Segoe UI,Roboto,sans-serif;color:#3c4043;margin-top:9px;">
          <strong style="color:#1a1a1a;">Business impact:</strong> ${esc(r.business_impact)}<br>
          <strong style="color:#1a1a1a;">Customer impact:</strong> ${esc(r.customer_impact)}<br>
          <strong style="color:#1a1a1a;">Action:</strong> ${esc(r.recommended_action)}
        </div>
        <div style="font:400 11px/1 -apple-system,Segoe UI,Roboto,sans-serif;color:#80868b;margin-top:11px;">
          Threat ${r.threat_level}/10 &nbsp;&middot;&nbsp; Opportunity ${r.opportunity_level}/10 &nbsp;&middot;&nbsp;
          Impact ${r.impact_score} &nbsp;&middot;&nbsp; Confidence ${r.confidence}/10 &nbsp;&middot;&nbsp;
          Sentiment ${esc(r.sentiment)}${r.ai_parse_failed ? ' &nbsp;&middot;&nbsp; <span style="color:#b3261e;">AI parse degraded</span>' : ''}
        </div>
      </td></tr>
    </table>
  </td></tr>`;
}

function section(label, list) {
  if (!list.length) return '';
  return `
  <tr><td style="padding:20px 0 10px;">
    <div style="font:700 12px/1 -apple-system,Segoe UI,Roboto,sans-serif;color:#1a1a1a;letter-spacing:.1em;text-transform:uppercase;border-bottom:1px solid #e0e0e0;padding-bottom:7px;">
      ${label} <span style="color:#80868b;font-weight:400;">(${list.length})</span>
    </div>
  </td></tr>
  <tr><td><table width="100%" cellpadding="0" cellspacing="0">${list.map(card).join('')}</table></td></tr>`;
}

const actions = rows
  .filter((r) => r.priority === 'Critical' || r.priority === 'High')
  .map((r) => `<li style="margin-bottom:7px;"><strong>${esc(r.company)}:</strong> ${esc(r.recommended_action)}</li>`)
  .join('') || '<li style="color:#80868b;">No high-priority actions today.</li>';

const html = `<!DOCTYPE html><html><body style="margin:0;padding:24px;background:#f1f3f4;">
<table width="100%" cellpadding="0" cellspacing="0"><tr><td align="center">
<table width="660" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:4px;padding:30px 34px;max-width:660px;">

  <tr><td style="padding-bottom:6px;">
    <div style="font:700 20px/1.3 -apple-system,Segoe UI,Roboto,sans-serif;color:#1a1a1a;">Competitive Intelligence Brief</div>
    <div style="font:400 13px/1.5 -apple-system,Segoe UI,Roboto,sans-serif;color:#80868b;margin-top:3px;">
      ${runDate} &nbsp;&middot;&nbsp; ${rows.length} new items &nbsp;&middot;&nbsp; ${companies.length} competitors tracked
    </div>
  </td></tr>

  <tr><td style="padding:16px 0 4px;">
    <table width="100%" cellpadding="0" cellspacing="0" style="background:#f8f9fa;border-radius:3px;">
      <tr><td style="padding:14px 16px;font:400 14px/1.6 -apple-system,Segoe UI,Roboto,sans-serif;color:#3c4043;">
        <strong style="color:#1a1a1a;">Executive summary.</strong>
        ${rows.length} new updates across ${esc(companies.join(', '))}.
        ${criticals.length ? `<strong style="color:#b3261e;">${criticals.length} critical.</strong>` : 'Nothing critical.'}
        Average threat level ${avgThreat}/10.
        ${criticals.length ? '<br><br>' + criticals.map((c) => '&bull; ' + esc(c.executive_summary)).join('<br>') : ''}
      </td></tr>
    </table>
  </td></tr>

  ${section('Critical', rows.filter((r) => r.priority === 'Critical'))}
  ${section('High priority', rows.filter((r) => r.priority === 'High'))}
  ${section('Medium priority', rows.filter((r) => r.priority === 'Medium'))}
  ${section('Low priority', rows.filter((r) => r.priority === 'Low'))}

  <tr><td style="padding:22px 0 8px;">
    <div style="font:700 12px/1 -apple-system,Segoe UI,Roboto,sans-serif;color:#1a1a1a;letter-spacing:.1em;text-transform:uppercase;border-bottom:1px solid #e0e0e0;padding-bottom:7px;">Recommended actions</div>
  </td></tr>
  <tr><td style="font:400 14px/1.55 -apple-system,Segoe UI,Roboto,sans-serif;color:#3c4043;">
    <ul style="margin:8px 0 0;padding-left:20px;">${actions}</ul>
  </td></tr>

  <tr><td style="padding-top:26px;border-top:1px solid #e0e0e0;margin-top:20px;">
    <div style="font:400 11px/1.5 -apple-system,Segoe UI,Roboto,sans-serif;color:#9aa0a6;">
      Generated by the AI Competitive Intelligence workflow. Sources: company RSS, GitHub API, Hacker News, Google News.
      Priority is rule-based; threat and opportunity scores are model-generated and advisory.
    </div>
  </td></tr>

</table></td></tr></table></body></html>`;

const subject = criticals.length
  ? `[CRITICAL] Competitive Brief ${runDate} - ${criticals.length} critical, ${rows.length} updates`
  : `Competitive Brief ${runDate} - ${rows.length} updates`;

return [{ json: { html, subject, total: rows.length, critical_count: criticals.length,
                  run_date: runDate, generated_at: new Date().toISOString() } }];
